class Solution:
    def flipLights(self, n, presses):
        m = min(n, 6)
        start = tuple([1] * m)
        def apply(state, b):
            s = list(state)
            for i in range(m):
                label = i + 1
                if b == 0:
                    s[i] ^= 1
                elif b == 1:
                    if label % 2 == 0:
                        s[i] ^= 1
                elif b == 2:
                    if label % 2 == 1:
                        s[i] ^= 1
                else:
                    if label % 3 == 1:
                        s[i] ^= 1
            return tuple(s)
        cur = {start}
        for _ in range(min(presses, 4)):
            nxt = set()
            for st in cur:
                for b in range(4):
                    nxt.add(apply(st, b))
            cur = nxt
        return len(cur)

