class Solution:
    def flipLights(self, n, presses):
        m = min(n, 3)
        reachable = set()
        for mask in range(16):
            cnt = bin(mask).count('1')
            if cnt > presses:
                continue
            if (presses - cnt) % 2 != 0:
                continue
            state = [1] * m
            for i in range(m):
                label = i + 1
                if mask & 1:
                    state[i] ^= 1
                if mask & 2 and label % 2 == 0:
                    state[i] ^= 1
                if mask & 4 and label % 2 == 1:
                    state[i] ^= 1
                if mask & 8 and label % 3 == 1:
                    state[i] ^= 1
            reachable.add(tuple(state))
        return len(reachable)

