var flipLights = function(n, presses) {
    const m = Math.min(n, 3);
    const reachable = new Set();
    for (let mask = 0; mask < 16; mask++) {
        let cnt = 0;
        for (let b = 0; b < 4; b++) if (mask & (1 << b)) cnt++;
        if (cnt > presses) continue;
        if ((presses - cnt) % 2 !== 0) continue;
        const state = [];
        for (let i = 0; i < m; i++) {
            const label = i + 1;
            let v = 1;
            if (mask & 1) v ^= 1;
            if ((mask & 2) && label % 2 === 0) v ^= 1;
            if ((mask & 4) && label % 2 === 1) v ^= 1;
            if ((mask & 8) && label % 3 === 1) v ^= 1;
            state.push(v);
        }
        reachable.add(state.join(','));
    }
    return reachable.size;
};
